  1	import * as React from 'react';
  2	import { NOOBAA_PROVISIONER } from '@odf/core/constants';
  3	import { projectResource } from '@odf/core/resources';
  4	import { BucketClassKind, ObjectBucketClaimKind } from '@odf/core/types';
  5	import {
  6	  createNewObjectBucketClaim,
  7	  createNewSingleNamespaceBucketClass,
  8	  generateGenericName,
  9	  getStorageClassDescription,
 10	} from '@odf/core/utils';
 11	import {
 12	  NooBaaObjectBucketClaimModel,
 13	  NooBaaBucketClassModel,
 14	} from '@odf/shared';
 15	import { formSettings, DEFAULT_NS } from '@odf/shared/constants';
 16	import ResourceDropdown from '@odf/shared/dropdown/ResourceDropdown';
 17	import ResourcesDropdown from '@odf/shared/dropdown/ResourceDropdown';
 18	import { FormGroupController } from '@odf/shared/form-group-controller';
 19	import { ButtonBar } from '@odf/shared/generic/ButtonBar';
 20	import { TextInputWithFieldRequirements } from '@odf/shared/input-with-requirements';
 21	import { ProjectModel, StorageClassModel } from '@odf/shared/models';
 22	import { getName } from '@odf/shared/selectors';
 23	import { K8sResourceKind, StorageClassResourceKind } from '@odf/shared/types';
 24	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 25	import { referenceForModel, ALL_NAMESPACES_KEY } from '@odf/shared/utils';
 26	import { useYupValidationResolver } from '@odf/shared/yup-validation-resolver';
 27	import {
 28	  getAPIVersionForModel,
 29	  k8sCreate,
 30	  K8sResourceCommon,
 31	  NamespaceBar,
 32	  useActiveNamespace,
 33	} from '@openshift-console/dynamic-plugin-sdk';
 34	import * as _ from 'lodash-es';
 35	import { Helmet } from 'react-helmet';
 36	import { Control, useForm } from 'react-hook-form';
 37	import { useNavigate } from 'react-router-dom-v5-compat';
 38	import {
 39	  ActionGroup,
 40	  Button,
 41	  Checkbox,
 42	  TextVariants,
 43	  Text,
 44	  Form,
 45	  FormGroup,
 46	  Alert,
 47	  TextContent,
 48	} from '@patternfly/react-core';
 49	import NamespaceSafetyBox from '../../components/utils/safety-box';
 50	import { useODFNamespaceSelector } from '../../redux';
 51	import { isObjectSC } from '../../utils';
 52	import { ReplicationPolicyForm, Rule } from './replication-policy-form';
 53	import {
 54	  Action,
 55	  commonReducer,
 56	  defaultState,
 57	  OBCReplicationRules,
 58	  ReplicationResources,
 59	  ReplicationRuleFormData,
 60	  State,
 61	  LogReplicationInfo,
 62	  OBCLogReplicationInfo,
 63	} from './state';
 64	import './create-obc.scss';
 65	import '../../style.scss';
 66	import useObcFormSchema from './useObcFormSchema';
 67	
 68	const storageClassResource = {
 69	  kind: StorageClassModel.kind,
 70	  namespaced: false,
 71	  isList: true,
 72	};
 73	
 74	const bucketClassResource = (ns: string) => ({
 75	  kind: referenceForModel(NooBaaBucketClassModel),
 76	  namespaced: true,
 77	  isList: true,
 78	  namespace: ns,
 79	});
 80	
 81	type CreateOBCFormProps = {
 82	  state: State;
 83	  dispatch: React.Dispatch<Action>;
 84	  namespace?: string;
 85	  control: Control;
 86	  fieldRequirements: string[];
 87	};
 88	
 89	const createReplicationRulesAndStringify = (
 90	  data: ReplicationRuleFormData[],
 91	  namespace: string,
 92	  logReplicationInfo: LogReplicationInfo
 93	): string => {
 94	  const rules: Array<OBCReplicationRules> = data.map((rule) => ({
 95	    ruleId: `rule-${rule.ruleNumber}`,
 96	    destination_bucket: `obc-${namespace}-${generateGenericName(
 97	      rule.namespaceStore,
 98	      'destination-bucket'
 99	    )}`,
100	    filter: {
101	      prefix: rule.prefix,
102	    },
103	    sync_deletions: rule.syncDeletion,
104	  }));
105	
106	  const obcLogReplicationInfo: OBCLogReplicationInfo = !_.isEmpty(
107	    logReplicationInfo
108	  )
109	    ? {
110	        logs_location: {
111	          logs_bucket: logReplicationInfo.logLocation,
112	          prefix: logReplicationInfo.logPrefix,
113	        },
114	      }
115	    : { logs_location: { logs_bucket: null, prefix: null } };
116	
117	  return rules
118	    ? JSON.stringify({ rules: [...rules], obcLogReplicationInfo })
119	    : '';
120	};
121	
122	const generateAdditionalReplicationResources = (
123	  state: State,
124	  namespace: string
125	): Array<ReplicationResources> => {
126	  return state.replicationRuleFormData.map((rule) => {
127	    const bc = createNewSingleNamespaceBucketClass(
128	      generateGenericName(rule.namespaceStore, 'generic-bucketclass'),
129	      namespace,
130	      rule.namespaceStore
131	    );
132	    const obc = createNewObjectBucketClaim(
133	      generateGenericName(rule.namespaceStore, 'destination-bucket'),
134	      namespace,
135	      getName(bc),
136	      state.scName
137	    );
138	    const res: ReplicationResources = {
139	      bucketClass: bc as BucketClassKind,
140	      objectBucketClaim: obc as ObjectBucketClaimKind,
141	    };
142	    return res;
143	  });
144	};
