 92	  logReplicationInfo: LogReplicationInfo
 93	): string => {
 94	  const rules: Array<OBCReplicationRules> = data.map((rule) => ({
 95	    ruleId: `rule-${rule.ruleNumber}`,
 96	    destination_bucket: `obc-${namespace}-${generateGenericName(
 97	      rule.namespaceStore,
 98	      'destination-bucket'
 99	    )}`,
100	    filter: {
101	      prefix: rule.prefix,
102	    },
103	    sync_deletions: rule.syncDeletion,
104	  }));
105	
106	  const obcLogReplicationInfo: OBCLogReplicationInfo = !_.isEmpty(
107	    logReplicationInfo
108	  )
109	    ? {
110	        logs_location: {
111	          logs_bucket: logReplicationInfo.logLocation,
112	          prefix: logReplicationInfo.logPrefix,
113	        },
114	      }
115	    : { logs_location: { logs_bucket: null, prefix: null } };
116	
117	  return rules
118	    ? JSON.stringify({ rules: [...rules], obcLogReplicationInfo })
119	    : '';
120	};
121	
122	const generateAdditionalReplicationResources = (
123	  state: State,
124	  namespace: string
125	): Array<ReplicationResources> => {
126	  return state.replicationRuleFormData.map((rule) => {
127	    const bc = createNewSingleNamespaceBucketClass(
128	      generateGenericName(rule.namespaceStore, 'generic-bucketclass'),
129	      namespace,
130	      rule.namespaceStore
131	    );
132	    const obc = createNewObjectBucketClaim(
133	      generateGenericName(rule.namespaceStore, 'destination-bucket'),
134	      namespace,
135	      getName(bc),
136	      state.scName
137	    );
138	    const res: ReplicationResources = {
139	      bucketClass: bc as BucketClassKind,
140	      objectBucketClaim: obc as ObjectBucketClaimKind,
141	    };
142	    return res;
143	  });
144	};
