146	export const CreateOBCForm: React.FC<CreateOBCFormProps> = (props) => {
147	  const { t } = useCustomTranslation();
148	  const { state, dispatch, namespace, control, fieldRequirements } = props;
149	  const isNoobaa = state.scProvisioner?.includes(NOOBAA_PROVISIONER);
150	
151	  const { odfNamespace } = useODFNamespaceSelector();
152	
153	  const onScChange = (sc, setScName: (value: string) => void) => {
154	    const scName = getName(sc);
155	    setScName(scName);
156	    dispatch({ type: 'setStorage', name: scName });
157	    dispatch({ type: 'setProvisioner', name: sc?.provisioner });
158	  };
159	
160	  const [replicationEnabled, toggleReplication] = React.useState(false);
161	
162	  const updateReplicationPolicy = (
163	    rules: Rule[],
164	    logReplicationInfo?: LogReplicationInfo
165	  ) => {
166	    let rulesFormData: Array<ReplicationRuleFormData> = [];
167	    rules.forEach((rule) => {
168	      if (rule.namespaceStore)
169	        rulesFormData.push({
170	          ruleNumber: rule.id,
171	          namespaceStore: rule.namespaceStore,
172	          prefix: rule.prefix,
173	          syncDeletion: rule.syncDeletion,
174	        });
175	    });
176	    dispatch({ type: 'setReplicationRuleFormData', data: rulesFormData });
177	    if (
178	      !_.isEmpty(logReplicationInfo) ||
179	      !rules.some((rule) => rule.syncDeletion)
180	    ) {
181	      dispatch({
182	        type: 'setLogReplicationInfo',
183	        data: { ...logReplicationInfo },
184	      });
185	    }
186	  };
187	
188	  React.useEffect(() => {
189	    const obj: K8sResourceKind = {
190	      apiVersion: getAPIVersionForModel(NooBaaObjectBucketClaimModel),
191	      kind: NooBaaObjectBucketClaimModel.kind,
192	      metadata: {
193	        namespace,
194	      },
195	      spec: {},
196	    };
197	    if (state.scName) {
198	      obj.spec.storageClassName = state.scName;
199	    }
200	    if (state.name) {
201	      obj.metadata.name = state.name;
202	      obj.spec.generateBucketName = state.name;
203	    } else {
204	      obj.metadata.generateName = 'bucketclaim-';
205	      obj.spec.generateBucketName = 'bucket-';
206	    }
207	    if (state.bucketClass && isNoobaa) {
208	      if (!!state.replicationRuleFormData.length) {
209	        const replicationPolicy = createReplicationRulesAndStringify(
210	          state.replicationRuleFormData,
211	          namespace,
212	          state.logReplicationInfo
213	        );
214	        obj.spec.additionalConfig = { replication_policy: replicationPolicy };
215	      }
216	      obj.spec.additionalConfig = {
217	        ...obj.spec.additionalConfig,
218	        bucketclass: state.bucketClass,
219	      };
220	    }
221	    dispatch({ type: 'setPayload', payload: obj });
222	  }, [
223	    namespace,
224	    state.name,
225	    state.scName,
226	    state.bucketClass,
227	    isNoobaa,
228	    dispatch,
229	    state.replicationRuleFormData,
230	    state.logReplicationInfo,
231	  ]);
232	
233	  const onChangeReplication = React.useCallback(() => {
234	    // if this checkbox is disabled, then on this point we purge the contents of replication form data
235	    if (replicationEnabled)
236	      dispatch({
237	        type: 'setReplicationRuleFormData',
238	        data: [],
239	      });
240	    toggleReplication(!replicationEnabled);
241	  }, [replicationEnabled, dispatch]);
242	
243	  const filterResource = React.useCallback(
244	    (sc: StorageClassResourceKind) => isObjectSC(sc, odfNamespace),
245	    [odfNamespace]
246	  );
247	
248	  return (
249	    <>
250	      <TextInputWithFieldRequirements
251	        control={control}
252	        fieldRequirements={fieldRequirements}
253	        popoverProps={{
254	          headerContent: t('Name requirements'),
255	          footerContent: `${t('Example')}: my-object-bucket`,
256	        }}
257	        formGroupProps={{
258	          label: t('ObjectBucketClaim Name'),
259	          fieldId: 'obc-name',
260	          className: 'control-label',
261	        }}
262	        textInputProps={{
263	          id: 'obc-name',
264	          name: 'obcName',
265	          className: 'pf-v6-c-form-control',
266	          type: 'text',
267	          placeholder: t('my-object-bucket'),
268	          'aria-describedby': 'obc-name-help',
269	          'data-test': 'obc-name',
270	        }}
271	        helperText={t('If not provided a generic name will be generated.')}
272	      />
273	      <FormGroupController
274	        name="sc-dropdown"
275	        control={control}
276	        formGroupProps={{
277	          fieldId: 'sc-dropdown',
278	          label: t('StorageClass'),
279	          helperText: t(
280	            'Defines the object-store service and the bucket provisioner.'
281	          ),
282	          isRequired: true,
283	        }}
284	        render={({ onChange, onBlur }) => (
285	          <ResourcesDropdown<StorageClassResourceKind>
286	            resourceModel={StorageClassModel}
287	            onSelect={(res) => onScChange(res, onChange)}
288	            onBlur={onBlur}
289	            filterResource={filterResource}
290	            initialSelection={(resources) =>
291	              resources?.find((res) =>
292	                res.provisioner.includes(NOOBAA_PROVISIONER)
293	              )
294	            }
295	            className="odf-mcg__resource-dropdown"
296	            id="sc-dropdown"
297	            data-test="sc-dropdown"
298	            resource={storageClassResource}
299	            secondaryTextGenerator={getStorageClassDescription}
300	          />
301	        )}
302	      />
303	      {isNoobaa && (
304	        <>
305	          <FormGroupController
306	            name="bucketclass"
307	            control={control}
308	            formGroupProps={{
309	              label: t('BucketClass'),
310	              isRequired: true,
311	            }}
312	            render={({ onChange, onBlur }) => (
313	              <ResourceDropdown<K8sResourceKind>
314	                onSelect={(sc) => {
315	                  onChange(sc.metadata?.name);
316	                  dispatch({
317	                    type: 'setBucketClass',
318	                    name: sc.metadata?.name,
319	                  });
320	                }}
321	                onBlur={onBlur}
322	                className="odf-mcg__resource-dropdown"
323	                initialSelection={(resources) =>
324	                  resources.find(
325	                    (res) => res.metadata.name === 'noobaa-default-bucket-class'
326	                  )
327	                }
328	                id="bc-dropdown"
329	                data-test="bc-dropdown"
330	                resource={bucketClassResource(odfNamespace)}
331	                resourceModel={NooBaaBucketClassModel}
332	              />
333	            )}
334	          />
335	          {isNoobaa && (
336	            <FormGroup>
337	              <Checkbox
338	                id="enable-replication"
339	                label={t('Enable replication')}
340	                isChecked={replicationEnabled}
341	                description={t(
342	                  'This option provides higher resiliency of objects stored in NooBaa buckets'
343	                )}
344	                onChange={onChangeReplication}
345	              />
346	            </FormGroup>
347	          )}
348	          {replicationEnabled && (
349	            <>
350	              <FormGroup>
351	                <Text component={TextVariants.h2}>
352	                  {t('Replication policy')}
353	                </Text>
354	              </FormGroup>
355	              <ReplicationPolicyForm
356	                className="form-group"
357	                namespace={namespace}
358	                updateParentState={updateReplicationPolicy}
359	              />
360	            </>
361	          )}
362	        </>
363	      )}
364	    </>
365	  );
366	};
367	
368	type CreateOBCProps = {
369	  className?: string;
370	  showNamespaceSelector?: boolean;
371	};
372	
373	export const CreateOBC: React.FC<CreateOBCProps> = ({
374	  className,
375	  showNamespaceSelector = false,
376	}) => {
377	  const { t } = useCustomTranslation();
378	  const [state, dispatch] = React.useReducer(commonReducer, defaultState);
379	  const [projectNs, setProjectNs] = useActiveNamespace();
380	  const { odfNamespace } = useODFNamespaceSelector();
381	  const [namespace, setNamespace] = React.useState(
382	    showNamespaceSelector ? odfNamespace : projectNs
383	  );
384	  // Keep form namespace in sync with project ns when ns form selector is not shown.
385	  if (!showNamespaceSelector && projectNs !== namespace) {
386	    setNamespace(projectNs);
387	  }
388	
389	  const isAllProjectsInitially = React.useRef<boolean>(
390	    namespace === ALL_NAMESPACES_KEY
391	  );
392	  const initialNamespace = React.useRef<string>(namespace);
393	  const submitBtnId = 'obc-submit-btn';
394	  const navigate = useNavigate();
395	  const { obcFormSchema, fieldRequirements } = useObcFormSchema(
396	    namespace,
397	    state
398	  );
399	
400	  const resolver = useYupValidationResolver(obcFormSchema);
401	
402	  const {
403	    control,
404	    handleSubmit,
405	    watch,
406	    formState: { isValid, isSubmitted },
407	  } = useForm({
408	    ...formSettings,
409	    resolver,
410	  });
411	
412	  const obcName: string = watch('obcName');
413	
414	  React.useEffect(() => {
415	    dispatch({ type: 'setName', name: obcName });
416	  }, [obcName, dispatch]);
417	
418	  /**
419	   * In OCP, for any creation page: on changing the project from the dropdown,
420	   * user is redirected back to the list page, added "() => navigate(-1)" to maintain that consistency.
421	   * Also, if initial selection is "All Projects", it automatically re-selects "default" as the initial project.
422	   */
423	  React.useEffect(() => {
424	    if (showNamespaceSelector) {
425	      return;
426	    }
427	    if (isAllProjectsInitially.current) {
428	      setProjectNs(DEFAULT_NS);
429	      initialNamespace.current = DEFAULT_NS;
430	      isAllProjectsInitially.current = false;
431	    } else if (initialNamespace.current !== namespace) {
432	      navigate(
433	        `/odf/object-storage/${referenceForModel(NooBaaObjectBucketClaimModel)}`
434	      );
435	    }
436	  }, [navigate, namespace, setProjectNs, showNamespaceSelector]);
437	
438	  const save = (
439	    _unused: any,
440	    e: React.SyntheticEvent<HTMLFormElement, SubmitEvent>
441	  ) => {
442	    e.preventDefault();
443	
444	    // NamespaceStore modal's submit is triggering this form as well, added this check to prevent that
445	    if (e.nativeEvent.submitter.id !== submitBtnId) return;
446	
447	    dispatch({ type: 'setProgress' });
448	    const promises: Promise<K8sResourceKind>[] = [];
449	    if (!!state.replicationRuleFormData.length) {
450	      const additionalResources = generateAdditionalReplicationResources(
451	        state,
452	        namespace
453	      );
454	
455	      additionalResources.forEach((res) => {
456	        promises.push(
457	          k8sCreate<K8sResourceKind>({
458	            model: NooBaaBucketClassModel,
459	            data: res.bucketClass,
460	          })
461	        );
462	
463	        promises.push(
464	          k8sCreate<K8sResourceKind>({
465	            model: NooBaaObjectBucketClaimModel,
466	            data: res.objectBucketClaim,
467	          })
468	        );
469	      });
470	    }
471	    Promise.all(promises)
472	      .then(() => {
473	        k8sCreate<K8sResourceKind>({
474	          model: NooBaaObjectBucketClaimModel,
475	          data: state.payload,
476	        })
477	          .then((resource) => {
478	            dispatch({ type: 'unsetProgress' });
479	            //@TODO: update the resource path with the new bucket details path.
480	            const resourcePath = `${referenceForModel(
481	              NooBaaObjectBucketClaimModel
482	            )}/${resource.metadata.name}`;
483	            navigate(
484	              `/odf/resource/ns/${resource.metadata.namespace}/${resourcePath}`
485	            );
486	          })
487	          .catch((err) => {
488	            dispatch({ type: 'setError', message: err.message });
489	            dispatch({ type: 'unsetProgress' });
490	          });
491	      })
492	      .catch((err) => {
493	        dispatch({ type: 'setError', message: err.message });
494	        dispatch({ type: 'unsetProgress' });
495	      });
496	  };
497	
498	  // Operator install namespace is determined using Subscriptions, which non-admin can not access.
499	  // Using "allowFallback" in "NamespaceSafetyBox" so that they can default to "openshift-storage" (if case of access issues),
500	  // which is current use case as well (as we do not officially support UI if ODF is installed in any other Namespace).
501	  // ToDo (Sanjal): Update the non-admin "Role" to a "ClusterRole", then read list of NooBaa/BucketClasses across all namespaces.
502	  return (
503	    <NamespaceSafetyBox allowFallback>
504	      <Form onSubmit={handleSubmit(save)} className={className}>
505	        {showNamespaceSelector && (
506	          <FormGroupController
507	            name="ns-dropdown"
508	            control={control}
509	            formGroupProps={{
510	              fieldId: 'ns-dropdown',
511	              label: t('Namespace'),
512	              helperText: t(
513	                'A namespace controls access to the OBC and ties the buckets to a specific project.'
514	              ),
515	              isRequired: true,
516	            }}
517	            render={({ onBlur }) => (
518	              <ResourcesDropdown<K8sResourceCommon>
519	                resourceModel={ProjectModel}
520	                onSelect={(selectedNamespace) =>
521	                  setNamespace(getName(selectedNamespace))
522	                }
523	                onBlur={onBlur}
524	                initialSelection={(resources) =>
525	                  resources?.find((res) => getName(res) === namespace)
526	                }
527	                className="odf-mcg__resource-dropdown"
528	                id="ns-dropdown"
529	                data-test="ns-dropdown"
530	                resource={projectResource}
531	              />
532	            )}
533	          />
534	        )}
535	        <CreateOBCForm
536	          state={state}
537	          dispatch={dispatch}
538	          namespace={namespace}
539	          control={control}
540	          fieldRequirements={fieldRequirements}
541	        />
542	        {!isValid && isSubmitted && (
543	          <Alert
544	            variant="danger"
545	            isInline
546	            title={t('Address form errors to proceed')}
547	          />
548	        )}
549	        <ButtonBar errorMessage={state.error} inProgress={state.progress}>
550	          <ActionGroup className="pf-v6-c-form">
551	            <Button
552	              id={submitBtnId}
553	              type="submit"
554	              variant="primary"
555	              data-test="obc-create"
556	            >
557	              {t('Create')}
558	            </Button>
559	            <Button
560	              onClick={() => navigate(-1)}
561	              type="button"
562	              variant="secondary"
563	            >
564	              {t('Cancel')}
565	            </Button>
566	          </ActionGroup>
567	        </ButtonBar>
568	      </Form>
569	    </NamespaceSafetyBox>
570	  );
571	};
572	
573	export const CreateOBCPage: React.FC<{}> = () => {
574	  const { t } = useCustomTranslation();
575	
576	  return (
577	    <>
578	      <NamespaceBar />
579	      <div className="odf-m-pane__body odf-m-pane__form">
580	        <Helmet>
581	          <title>{t('Create ObjectBucketClaim')}</title>
582	        </Helmet>
583	        <TextContent className="odf-m-pane__heading odf-m-pane__heading--baseline">
584	          <Text component={TextVariants.h1}>
585	            {t('Create ObjectBucketClaim')}
586	          </Text>
587	        </TextContent>
588	        <CreateOBC />
589	      </div>
590	    </>
591	  );
592	};

