  1	import * as React from 'react';
  2	import { NOOBAA_PROVISIONER } from '@odf/core/constants';
  3	import { projectResource } from '@odf/core/resources';
  4	import { BucketClassKind, ObjectBucketClaimKind } from '@odf/core/types';
  5	import {
  6	  createNewObjectBucketClaim,
  7	  createNewSingleNamespaceBucketClass,
  8	  generateGenericName,
  9	  getStorageClassDescription,
 10	} from '@odf/core/utils';
 11	import {
 12	  NooBaaObjectBucketClaimModel,
 13	  NooBaaBucketClassModel,
 14	} from '@odf/shared';
 15	import { formSettings, DEFAULT_NS } from '@odf/shared/constants';
 16	import ResourceDropdown from '@odf/shared/dropdown/ResourceDropdown';
 17	import ResourcesDropdown from '@odf/shared/dropdown/ResourceDropdown';
 18	import { FormGroupController } from '@odf/shared/form-group-controller';
 19	import { ButtonBar } from '@odf/shared/generic/ButtonBar';
 20	import { TextInputWithFieldRequirements } from '@odf/shared/input-with-requirements';
 21	import { ProjectModel, StorageClassModel } from '@odf/shared/models';
 22	import { getName } from '@odf/shared/selectors';
 23	import { K8sResourceKind, StorageClassResourceKind } from '@odf/shared/types';
 24	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 25	import { referenceForModel, ALL_NAMESPACES_KEY } from '@odf/shared/utils';
 26	import { useYupValidationResolver } from '@odf/shared/yup-validation-resolver';
 27	import {
 28	  getAPIVersionForModel,
 29	  k8sCreate,
 30	  K8sResourceCommon,
 31	  NamespaceBar,
 32	  useActiveNamespace,
 33	} from '@openshift-console/dynamic-plugin-sdk';
 34	import * as _ from 'lodash-es';
 35	import { Helmet } from 'react-helmet';
 36	import { Control, useForm } from 'react-hook-form';
 37	import { useNavigate } from 'react-router-dom-v5-compat';
 38	import {
 39	  ActionGroup,
 40	  Button,
 41	  Checkbox,
 42	  ContentVariants,
 43	  Content,
 44	  Form,
 45	  FormGroup,
 46	  Alert,
 47	} from '@patternfly/react-core';
 48	import NamespaceSafetyBox from '../../components/utils/safety-box';
 49	import { useODFNamespaceSelector } from '../../redux';
 50	import { isObjectSC } from '../../utils';
 51	import { ReplicationPolicyForm, Rule } from './replication-policy-form';
 52	import {
 53	  Action,
 54	  commonReducer,
 55	  defaultState,
 56	  OBCReplicationRules,
 57	  ReplicationResources,
 58	  ReplicationRuleFormData,
 59	  State,
 60	  LogReplicationInfo,
 61	  OBCLogReplicationInfo,
 62	} from './state';
 63	import './create-obc.scss';
 64	import '../../style.scss';
 65	import useObcFormSchema from './useObcFormSchema';
 66	
 67	const storageClassResource = {
 68	  kind: StorageClassModel.kind,
 69	  namespaced: false,
 70	  isList: true,
 71	};
 72	
 73	const bucketClassResource = (ns: string) => ({
 74	  kind: referenceForModel(NooBaaBucketClassModel),
 75	  namespaced: true,
 76	  isList: true,
 77	  namespace: ns,
 78	});
 79	
 80	type CreateOBCFormProps = {
 81	  state: State;
 82	  dispatch: React.Dispatch<Action>;
 83	  namespace?: string;
 84	  control: Control;
 85	  fieldRequirements: string[];
 86	};
 87	
 88	const createReplicationRulesAndStringify = (
 89	  data: ReplicationRuleFormData[],
 90	  namespace: string,
 91	  logReplicationInfo: LogReplicationInfo
 92	): string => {
 93	  const rules: Array<OBCReplicationRules> = data.map((rule) => ({
 94	    ruleId: `rule-${rule.ruleNumber}`,
 95	    destination_bucket: `obc-${namespace}-${generateGenericName(
 96	      rule.namespaceStore,
 97	      'destination-bucket'
 98	    )}`,
 99	    filter: {
100	      prefix: rule.prefix,
101	    },
102	    sync_deletions: rule.syncDeletion,
103	  }));
104	
105	  const obcLogReplicationInfo: OBCLogReplicationInfo = !_.isEmpty(
106	    logReplicationInfo
107	  )
108	    ? {
109	        logs_location: {
110	          logs_bucket: logReplicationInfo.logLocation,
111	          prefix: logReplicationInfo.logPrefix,
112	        },
113	      }
114	    : { logs_location: { logs_bucket: null, prefix: null } };
115	
116	  return rules
117	    ? JSON.stringify({ rules: [...rules], obcLogReplicationInfo })
118	    : '';
119	};
120	
121	const generateAdditionalReplicationResources = (
122	  state: State,
123	  namespace: string
124	): Array<ReplicationResources> => {
125	  return state.replicationRuleFormData.map((rule) => {
126	    const bc = createNewSingleNamespaceBucketClass(
127	      generateGenericName(rule.namespaceStore, 'generic-bucketclass'),
128	      namespace,
129	      rule.namespaceStore
130	    );
131	    const obc = createNewObjectBucketClaim(
132	      generateGenericName(rule.namespaceStore, 'destination-bucket'),
133	      namespace,
134	      getName(bc),
135	      state.scName
136	    );
137	    const res: ReplicationResources = {
138	      bucketClass: bc as BucketClassKind,
139	      objectBucketClaim: obc as ObjectBucketClaimKind,
140	    };
141	    return res;
142	  });
143	};
144	
145	export const CreateOBCForm: React.FC<CreateOBCFormProps> = (props) => {
146	  const { t } = useCustomTranslation();
147	  const { state, dispatch, namespace, control, fieldRequirements } = props;
148	  const isNoobaa = state.scProvisioner?.includes(NOOBAA_PROVISIONER);
149	
150	  const { odfNamespace } = useODFNamespaceSelector();
151	
152	  const onScChange = (sc, setScName: (value: string) => void) => {
153	    const scName = getName(sc);
154	    setScName(scName);
155	    dispatch({ type: 'setStorage', name: scName });
156	    dispatch({ type: 'setProvisioner', name: sc?.provisioner });
157	  };
158	
159	  const [replicationEnabled, toggleReplication] = React.useState(false);
160	
161	  const updateReplicationPolicy = (
162	    rules: Rule[],
163	    logReplicationInfo?: LogReplicationInfo
164	  ) => {
165	    let rulesFormData: Array<ReplicationRuleFormData> = [];
166	    rules.forEach((rule) => {
167	      if (rule.namespaceStore)
168	        rulesFormData.push({
169	          ruleNumber: rule.id,
170	          namespaceStore: rule.namespaceStore,
171	          prefix: rule.prefix,
172	          syncDeletion: rule.syncDeletion,
173	        });
174	    });
175	    dispatch({ type: 'setReplicationRuleFormData', data: rulesFormData });
176	    if (
177	      !_.isEmpty(logReplicationInfo) ||
178	      !rules.some((rule) => rule.syncDeletion)
179	    ) {
180	      dispatch({
181	        type: 'setLogReplicationInfo',
182	        data: { ...logReplicationInfo },
183	      });
184	    }
185	  };
186	
187	  React.useEffect(() => {
188	    const obj: K8sResourceKind = {
189	      apiVersion: getAPIVersionForModel(NooBaaObjectBucketClaimModel),
190	      kind: NooBaaObjectBucketClaimModel.kind,
