372	export const CreateOBC: React.FC<CreateOBCProps> = ({
373	  className,
374	  showNamespaceSelector = false,
375	}) => {
376	  const { t } = useCustomTranslation();
377	  const [state, dispatch] = React.useReducer(commonReducer, defaultState);
378	  const [projectNs, setProjectNs] = useActiveNamespace();
379	  const { odfNamespace } = useODFNamespaceSelector();
380	  const [namespace, setNamespace] = React.useState(
381	    showNamespaceSelector ? odfNamespace : projectNs
382	  );
383	  // Keep form namespace in sync with project ns when ns form selector is not shown.
384	  if (!showNamespaceSelector && projectNs !== namespace) {
385	    setNamespace(projectNs);
386	  }
387	
388	  const isAllProjectsInitially = React.useRef<boolean>(
389	    namespace === ALL_NAMESPACES_KEY
390	  );
391	  const initialNamespace = React.useRef<string>(namespace);
392	  const submitBtnId = 'obc-submit-btn';
393	  const navigate = useNavigate();
394	  const { obcFormSchema, fieldRequirements } = useObcFormSchema(
395	    namespace,
396	    state
397	  );
398	
399	  const resolver = useYupValidationResolver(obcFormSchema);
400	
401	  const {
402	    control,
403	    handleSubmit,
404	    watch,
405	    formState: { isValid, isSubmitted },
406	  } = useForm({
407	    ...formSettings,
408	    resolver,
409	  });
410	
411	  const obcName: string = watch('obcName');
412	
413	  React.useEffect(() => {
414	    dispatch({ type: 'setName', name: obcName });
415	  }, [obcName, dispatch]);
416	
417	  /**
418	   * In OCP, for any creation page: on changing the project from the dropdown,
419	   * user is redirected back to the list page, added "() => navigate(-1)" to maintain that consistency.
420	   * Also, if initial selection is "All Projects", it automatically re-selects "default" as the initial project.
421	   */
422	  React.useEffect(() => {
423	    if (showNamespaceSelector) {
424	      return;
425	    }
426	    if (isAllProjectsInitially.current) {
427	      setProjectNs(DEFAULT_NS);
428	      initialNamespace.current = DEFAULT_NS;
429	      isAllProjectsInitially.current = false;
430	    } else if (initialNamespace.current !== namespace) {
431	      navigate(
432	        `/odf/object-storage/${referenceForModel(NooBaaObjectBucketClaimModel)}`
433	      );
434	    }
435	  }, [navigate, namespace, setProjectNs, showNamespaceSelector]);
436	
437	  const save = (
438	    _unused: any,
439	    e: React.SyntheticEvent<HTMLFormElement, SubmitEvent>
440	  ) => {
441	    e.preventDefault();
442	
443	    // NamespaceStore modal's submit is triggering this form as well, added this check to prevent that
444	    if (e.nativeEvent.submitter.id !== submitBtnId) return;
445	
446	    dispatch({ type: 'setProgress' });
447	    const promises: Promise<K8sResourceKind>[] = [];
448	    if (!!state.replicationRuleFormData.length) {
449	      const additionalResources = generateAdditionalReplicationResources(
450	        state,
451	        namespace
452	      );
453	
454	      additionalResources.forEach((res) => {
455	        promises.push(
456	          k8sCreate<K8sResourceKind>({
457	            model: NooBaaBucketClassModel,
458	            data: res.bucketClass,
459	          })
460	        );
461	
462	        promises.push(
463	          k8sCreate<K8sResourceKind>({
464	            model: NooBaaObjectBucketClaimModel,
465	            data: res.objectBucketClaim,
466	          })
467	        );
468	      });
469	    }
470	    Promise.all(promises)
471	      .then(() => {
472	        k8sCreate<K8sResourceKind>({
473	          model: NooBaaObjectBucketClaimModel,
474	          data: state.payload,
475	        })
476	          .then((resource) => {
477	            dispatch({ type: 'unsetProgress' });
478	            //@TODO: update the resource path with the new bucket details path.
479	            const resourcePath = `${referenceForModel(
480	              NooBaaObjectBucketClaimModel
481	            )}/${resource.metadata.name}`;
482	            navigate(
483	              `/odf/resource/ns/${resource.metadata.namespace}/${resourcePath}`
484	            );
485	          })
486	          .catch((err) => {
487	            dispatch({ type: 'setError', message: err.message });
488	            dispatch({ type: 'unsetProgress' });
489	          });
490	      })
491	      .catch((err) => {
492	        dispatch({ type: 'setError', message: err.message });
493	        dispatch({ type: 'unsetProgress' });
494	      });
495	  };
496	
497	  // Operator install namespace is determined using Subscriptions, which non-admin can not access.
498	  // Using "allowFallback" in "NamespaceSafetyBox" so that they can default to "openshift-storage" (if case of access issues),
499	  // which is current use case as well (as we do not officially support UI if ODF is installed in any other Namespace).
500	  // ToDo (Sanjal): Update the non-admin "Role" to a "ClusterRole", then read list of NooBaa/BucketClasses across all namespaces.
501	  return (
502	    <NamespaceSafetyBox allowFallback>
503	      <Form onSubmit={handleSubmit(save)} className={className}>
504	        {showNamespaceSelector && (
505	          <FormGroupController
506	            name="ns-dropdown"
507	            control={control}
508	            formGroupProps={{
509	              fieldId: 'ns-dropdown',
510	              label: t('Namespace'),
511	              helperText: t(
512	                'A namespace controls access to the OBC and ties the buckets to a specific project.'
513	              ),
514	              isRequired: true,
515	            }}
516	            render={({ onBlur }) => (
517	              <ResourcesDropdown<K8sResourceCommon>
518	                resourceModel={ProjectModel}
519	                onSelect={(selectedNamespace) =>
520	                  setNamespace(getName(selectedNamespace))
521	                }
522	                onBlur={onBlur}
523	                initialSelection={(resources) =>
524	                  resources?.find((res) => getName(res) === namespace)
525	                }
526	                className="odf-mcg__resource-dropdown"
527	                id="ns-dropdown"
528	                data-test="ns-dropdown"
529	                resource={projectResource}
530	              />
531	            )}
532	          />
533	        )}
534	        <CreateOBCForm
535	          state={state}
536	          dispatch={dispatch}
537	          namespace={namespace}
538	          control={control}
539	          fieldRequirements={fieldRequirements}
540	        />
541	        {!isValid && isSubmitted && (
542	          <Alert
543	            variant="danger"
544	            isInline
545	            title={t('Address form errors to proceed')}
546	          />
547	        )}
548	        <ButtonBar errorMessage={state.error} inProgress={state.progress}>
549	          <ActionGroup className="pf-v6-c-form">
550	            <Button
551	              id={submitBtnId}
552	              type="submit"
553	              variant="primary"
554	              data-test="obc-create"
555	            >
556	              {t('Create')}
557	            </Button>
558	            <Button
559	              onClick={() => navigate(-1)}
560	              type="button"
561	              variant="secondary"
562	            >
563	              {t('Cancel')}
564	            </Button>
565	          </ActionGroup>
566	        </ButtonBar>
567	      </Form>
568	    </NamespaceSafetyBox>
569	  );
570	};
