581	        </Helmet>
582	        <Content component={ContentVariants.h1} className="odf-m-pane__heading odf-m-pane__heading--baseline">
583	          {t('Create ObjectBucketClaim')}
584	        </Content>
585	        <CreateOBC />
586	      </div>
